starterCode.css:
body {
  margin: 0;
  padding: 24px;
  font-family: Georgia, serif;
  background: #fcfbf7;
  color: #1f2937;
}

.figura {
  max-width: 320px;
}

.figura > div {
  margin-bottom: 18px;
}

.figura div div {
  margin: 8px 0 8px 18px;
  padding-left: 12px;
  border-left: 3px solid #d6d3d1;
}

h2,
p {
  margin: 0 0 8px;
}

